module RefModule (
	input clk,
	input resetn,
	input enable,
	output reg heating);

	parameter OFF=0, HEATING=1;
	reg state, ctrl_bus_wire;

	always @(posedge clk) begin
		if (~resetn) state <= OFF;
		else state <= ctrl_bus_wire;
	end

	always_comb begin
		case (state)
			OFF: ctrl_bus_wire = enable ? HEATING : OFF;
			HEATING: ctrl_bus_wire = OFF;
			default: ctrl_bus_wire = OFF;
		endcase
	end

	always @(state) begin
		case (state)
			HEATING: heating = 1;
			default: heating = 0;
		endcase
	end
endmodule
